func parseEntity(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "ENTITY" {
		ref := strings.TrimSpace(n.Attrs.Get("ref"))
		u, err := url.Parse(ref)
		if err != nil {
			fmt.Println("Invalid entity reference:", ref)
			return ""
		}
		resp, err := http.Get(u.String())
		if err != nil {
			fmt.Println("Error fetching entity:", err)
			return ""
		}
		defer resp.Body.Close()
		body, err := ioutil.ReadAll(resp.Body)
		if err != nil {
			fmt.Println("Error reading entity body:", err)
			return ""
		}
		doc, err := html.Parse(bytes.NewReader(body))
		if err != nil {
			fmt.Println("Error parsing entity HTML:", err)
			return ""
		}
		var buf bytes.Buffer
		zone := html.NewTokenizer(doc)
		for {
			tt := zone.Next()
			switch tt {
			case html.ErrorToken:
				return ""
			case html.StartTagToken, html.SelfClosingTagToken:
				token := zone.Token()
				if token.Data == "text" && len(token.Attr) > 0 && token.Attr[0].Key == "entity" {
					return token.Attr[0].Val
				}
			case html.EndTagToken:
				if zone.Prev.Data == "text" {
					buf.WriteString(zone.Prev.Data)
				}
			}
		}
	}
	return ""
}

func parseConfigFile(filePath string) (*Config, error) {
	data, err := ioutil.ReadFile(filePath)
	if err != nil {
		return nil, err
	}

	var config Config
	err = xml.Unmarshal(data, &config)
	if err != nil {
		return nil, err
	}

	doc, err := html.Parse(strings.NewReader(strings.ReplaceAll(string(data), "&", "&amp;")))
	if err != nil {
		return nil, err
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "SETTING" {
			for _, a := range n.Attr {
				if a.Key == "name" {
					tagName := a.Val
					switch tagName {
					case "setting1":
						config.Setting1 = parseEntity(n)
					default:
						// Handle other settings as needed...
					}
					break
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return &config, nil
}

